content:
nextflow.enable.dsl=2

include { step_2AS_mapping__ivar } from '../steps/step_2AS_mapping__ivar'
include { step_4TY_lineage__pangolin } from '../steps/step_4TY_lineage__pangolin'
include { extractKey } from '../functions/common.nf'
include { getSingleInput } from '../functions/parameters.nf'

def referenceCode = 'NC_045512.2'
def referencePath = "${params.assets_dir}/module_covid_emergency/NC_045512.fasta"
def referenceRiscd = '220308-020220308005121273-2AS_import-external'

workflow module_covid_emergency {
    take: 
        trimmed
    main:
        trimmed.multiMap {
            trimmed: it
            reference: [ referenceRiscd, referenceCode, file(referencePath) ]
        }.set { trAndRef }
        consensus = step_2AS_mapping__ivar(trAndRef.trimmed, trAndRef.reference).consensus
        step_4TY_lineage__pangolin(consensus)
    }

workflow {
    module_covid_emergency(getSingleInput())
}

nextflow.enable.dsl=2

include { step_1PP_hostdepl__bowtie } from '../steps/step_1PP_hostdepl__bowtie'
include { step_2AS_denovo__spades } from '../steps/step_2AS_denovo__spades'
include { extractKey; getEmpty } from '../functions/common.nf'
include { getSingleInput;getHost } from '../functions/parameters.nf'

workflow module_denovo {
    take: 
        trimmedReads
        host 
    main:
        trimmedReads.cross(host) { extractKey(it) }
            .map { [ it[0][0], it[0][1], it[1][1] ] } //riscd, reads, host
            .branch {
                with_host: it[1][1]
                without_host: true
            }
        .set { branchedTrimmed }

        depleted = step_1PP_hostdepl__bowtie(branchedTrimmed.with_host)

        branchedTrimmed.without_host
            .mix(depleted)
            .map { it[0,1] }
            .set{ denovoInput }
        assembled = step_2AS_denovo__spades(denovoInput)
    emit:
        assembled
        depleted
}

workflow {
    module_denovo(getSingleInput(), getHost())
}

nextflow.enable.dsl=2

include { step_2AS_mapping__bowtie } from '../steps/step_2AS_mapping__bowtie'
include { step_2AS_mapping__ivar } from '../steps/step_2AS_mapping__ivar'
include { step_4AN_genes__prokka } from '../steps/step_4AN_genes__prokka'
include { step_4TY_lineage__pangolin } from '../steps/step_4TY_lineage__pangolin'
include { extractKey; getEmpty } from '../functions/common.nf'
include { getSingleInput;getReferenceOptional;getReference } from '../functions/parameters.nf'

def PROKKA_KINGDOM = 'Viruses'

workflow module_draft_genome {
    take: 
        reads
        reference 
        referenceGB
    main:
        reads.cross(reference) { extractKey(it) }.multiMap { 
            reads: it[0] // riscd, reads
            refs:  it[1][1..3] // riscd, code, path
        }.set { readsAndReferences }

        step_2AS_mapping__bowtie(readsAndReferences.reads, readsAndReferences.refs)

        consensus = step_2AS_mapping__ivar(readsAndReferences.reads, readsAndReferences.refs).consensus

        consensus.cross(referenceGB) { extractKey(it) }.map { 
            [ it[0][0], it[0][1], PROKKA_KINGDOM, it[1][1], it[1][2], it[1][3] ] // riscd assembly kingdom riscd_ref refid refpath]

        }.set { consensusKingdomReference }

        step_4AN_genes__prokka(consensusKingdomReference)
    }

workflow  {
    module_draft_genome(getSingleInput(), getReference('fa'), getReferenceOptional('gb'))
}

nextflow.enable.dsl=2

include { step_2AS_denovo__unicycler } from '../steps/step_2AS_denovo__unicycler'
include { step_4AN_AMR__blast } from '../steps/step_4AN_AMR__blast'
include { getSingleInput;getGenusSpeciesOptional } from '../functions/parameters.nf'
include { extractKey } from '../functions/common.nf'

workflow module_enterotoxin_saureus_finder {
    take: 
        trimmed
        genus_species
    main:
        assembly = step_2AS_denovo__unicycler(trimmed)

        assembly.cross(genus_species) { extractKey(it) }
            .multiMap { 
                assembly: it[0]
                species: it[1]
            }.set { assemblyAndSpecies }
        step_4AN_AMR__blast(assemblyAndSpecies.assembly, assemblyAndSpecies.species)
}

workflow {
    module_enterotoxin_saureus_finder(getSingleInput(), getGenusSpeciesOptional())
}

nextflow.enable.dsl=2

include { step_1PP_filtering__bowtie } from '../steps/step_1PP_filtering__bowtie'
include { step_2AS_denovo__spades } from '../steps/step_2AS_denovo__spades'
include { extractKey } from '../functions/common.nf'
include { getSingleInput;getReference } from '../functions/parameters.nf'

workflow module_filtered_denovo {
    take: 
        reads
        reference 
    main:
        reads.cross(reference) { extractKey(it) }.multiMap { 
            reads: it[0] // riscd, reads
            refs:  it[1][1..3] // riscd, code, path
        }.set { readsAndReferences }

        filtered = step_1PP_filtering__bowtie(readsAndReferences.reads, readsAndReferences.refs)
        assembled = step_2AS_denovo__spades(filtered)
    emit:
        assembled
        filtered
}

workflow {
    module_filtered_denovo(getSingleInput(), getReference('fa'))
}

nextflow.enable.dsl=2

include { parseRISCD;taskMemory } from '../functions/common.nf'
include { _getAlleles;param } from '../functions/parameters.nf'

def GEO_RESOLUTION_COLUMNS = param('multi_clustering__reportree__summary_geo_column')
def SUMMARY_DATE_ALIASES = param('multi_clustering__reportree__summary_date_aliases')
def SAMPLE_COLUMN = param('multi_clustering__reportree__summary_sample_column')

process extract_cgMLST {
    container "ghcr.io/genpat-it/chewbbaca-w-chewie-schemas:2.8.5--16b816c96d"
    memory { taskMemory( 5.GB, task.attempt ) }
    input:
      path(alleles)
    output:
      path '**'
      path 'cgMLST.tsv', emit: cgMLST
      path '*.sh', hidden: true
    publishDir mode: 'copy', "${params.outdir}/result", pattern: 'mdata_stats.tsv', saveAs: { "missing_loci.tsv" }
    publishDir mode: 'copy', "${params.outdir}/result", pattern: 'cgMLST.tsv', saveAs: { "cgMLST.tsv" }
    publishDir mode: 'copy', "${params.outdir}/meta", pattern: '*.log'
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '.command.sh', saveAs: { "extract_cgMLST.cfg" }
    script:
      """
        for file in ${alleles} ; do awk 'FNR==1{print ""}1' \${file} | sed 's/,/\t/g' | sed -E "s/^[^SF][^ai]\\S+/\${file}/" | sed -E 's/DS[[:digit:]]+-DT[[:digit:]]+_([^_]+)_[[:graph:]]+/\\1/'; done | sort -ru  > results_alleles_all.tsv
        chewie ExtractCgMLST -i results_alleles_all.tsv -o . > extract_cgMLST.log
      """
}

process dists {
    container "quay.io/biocontainers/cgmlst-dists:0.4.0--hec16e2b_2"
    memory { taskMemory( 5.GB, task.attempt ) }
    input:
      path(cgMLST)
    output:
      path '*'
      path '{*.sh,*.log}', hidden: true
    publishDir mode: 'rellink', "${params.outdir}/result", pattern: '{*.csv}'
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '.command.log', saveAs: { "cgmlst-dists.log" }
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '.command.sh', saveAs: { "cgmlst-dists.cfg" }
    script:
      """
        cgmlst-dists -c ${cgMLST} > cgMLST_dists_matrix.csv
      """
}

process grapetree {
    container "quay.io/biocontainers/grapetree:2.1--pyh3252c3a_0"
    memory { taskMemory( 5.GB, task.attempt ) }
    input:
      path(cgMLST)
    output:
      path '*'
      path '*.sh', hidden: true
      path("cgMLST_NJ.nwk"), emit: nwk_nj
    publishDir mode: 'copy', "${params.outdir}/result", pattern: '*.nwk'
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '.command.sh', saveAs: { "grapetree.cfg" }
    script:
      """
        grapetree -p ${cgMLST} > cgMLST.nwk
        grapetree --method RapidNJ -p ${cgMLST} > cgMLST_NJ.nwk
      """
}

process augur {
    container "quay.io/biocontainers/augur:22.0.0--pyhdfd78af_0"
    memory { taskMemory( 4.GB, task.attempt ) }
    input:
      path(nwk)
      path(metadata)
      path(geodata)
    output:
      path '*'
      path '{*.sh,*.log}', hidden: true
    publishDir mode: 'rellink', "${params.outdir}/result", pattern: 'auspice.json'
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '*.log', saveAs: { "augur.log" }
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '.command.sh', saveAs: { "augur.cfg" }
    script:
      """
        cat ${metadata} | sed 's/${SAMPLE_COLUMN}/name/i' \
           | sed 's/${SUMMARY_DATE_ALIASES}/date/i' > augur_metadata.tsv
        METADATA_LIST=\$(head -n 1 augur_metadata.tsv | tr \$'\t' ' ')
        augur refine --tree ${nwk} --output-tree tree_tt.nwk --output-node-data refine.node.json --metadata augur_metadata.tsv
        augur export v2 --tree tree_tt.nwk --node-data refine.node.json --output auspice.json \
          --color-by-metadata \${METADATA_LIST} \
          --geo-resolutions ${GEO_RESOLUTION_COLUMNS} \
          --metadata augur_metadata.tsv \
          --lat-longs ${geodata}
      """
}

workflow multi_clustering__grapetree {
    take: 
        input
        metadata
        geodata
    main:
        cgMLST = extract_cgMLST(input.collect()).cgMLST
        dists(cgMLST)
        nwk_nj = grapetree(cgMLST).nwk_nj
        augur(nwk_nj, metadata, geodata)
}

workflow {
    multi_clustering__grapetree(getInput(), param('metadata'), param('geodata'));
}

def getInput() {
    if (!params.containsKey('input')) {
      exit 2, "missing required param: input";
    }
    def schema = params.containsKey('schema') ? params.schema : null
    assert params.input instanceof ArrayList
    params.input.inject(Channel.empty()) {
        res, val -> res.mix(_getAlleles(val.cmp, val.riscd, schema))
    }        
}

nextflow.enable.dsl=2

include { module_reads_processing } from '../modules/module_reads_processing'
include { module_wgs_bacteria } from '../modules/module_wgs_bacteria'
include { module_typing_bacteria } from '../modules/module_typing_bacteria'
include { module_covid_emergency } from '../modules/module_covid_emergency'
include { module_vdraft } from '../modules/module_vdraft'
include { module_westnile } from '../modules/module_westnile'
include { module_qc_quast } from '../modules/module_qc_quast'
include { step_4TY_lineage__pangolin } from '../steps/step_4TY_lineage__pangolin'


include { getSingleInput;param } from '../functions/parameters.nf'
include { getEmpty;extractKey;isFastqRiscd;isFastaRiscd } from '../functions/common.nf'
include { isNegativeControl;isNegativeControlSarsCov2;isPositiveControlSarsCov2;isVirus;isWNV;isBacterium;isSarsCov2;isAmpliseq } from '../functions/sampletypes.nf'

workflow ngsmanager_fastq {
    take: 
      rawReads  
    main:
      try {       
        trimmed = module_reads_processing(rawReads).trimmed_with_data

        trimmed.branch {
            bacteria: isBacterium(it)
            sarscov2: isSarsCov2(it) || isNegativeControlSarsCov2(it) || isPositiveControlSarsCov2(it)
            negative_control: isNegativeControl(it)
            viruses: isVirus(it)
            wnv: isWNV(it)
            ampliseq: isAmpliseq(it)
            other: true
        }
        .set { branched }

        /* bacteria stuff here */
        assemblyBacteria = module_wgs_bacteria(branched.bacteria)
        crossedBacteriaData = branched.bacteria.cross(assemblyBacteria) { extractKey(it) }.multiMap { 
          trimmed: it[0]
          assembly: it[1]
        }
        module_typing_bacteria(crossedBacteriaData.trimmed, crossedBacteriaData.assembly)

        /* sarscov2 stuff here */
        module_covid_emergency(branched.sarscov2)

        /* viruses stuff here */
        // no extra modules executed

        /* wnv stuff here */
        module_westnile(branched.wnv)
      } catch (t) {
          exit 1, "unexpected exception: ${t.asString()}"
      }

}

workflow ngsmanager_fasta {
    take: 
      fasta
    main:
      try {      
        module_qc_quast(fasta)

        fasta.branch {
            bacteria: isBacterium(it)
            sarscov2: isSarsCov2(it) || isNegativeControlSarsCov2(it) || isPositiveControlSarsCov2(it)
            negative_control: isNegativeControl(it)
            viruses: isVirus(it)
            wnv: isWNV(it)
            ampliseq: isAmpliseq(it)
            other: true
        }
        .set { branched }

        /* bacteria stuff here */
        module_typing_bacteria(Channel.empty(), branched.bacteria)

        /* sarscov2 stuff here */
        step_4TY_lineage__pangolin(branched.sarscov2)       

        /* wnv stuff here */
        module_westnile(branched.wnv)        
      } catch (t) {
          exit 1, "unexpected exception: ${t.asString()}"
      }     
}

workflow pipeline_ngsmanager {
  if (isFastqRiscd(param('riscd'))){
    ngsmanager_fastq(getSingleInput())
  } else if (isFastaRiscd(param('riscd'))){
    ngsmanager_fasta(getSingleInput())
  } else {
    exit 2, "unexpected riscd provided: ${param('riscd')}"
  }
}

workflow {
  pipeline_ngsmanager()
}

nextflow.enable.dsl=2

include { step_4TY_plasmid__mobsuite } from '../steps/step_4TY_plasmid__mobsuite'
include { isSpeciesSupported;taskMemory;flattenPath;parseMetadataFromFileName;executionMetadata } from '../functions/common.nf'
include { getSingleInput;isIlluminaPaired;isCompatibleWithSeqType;isIonTorrent;param } from '../functions/parameters.nf'

POINFINDER_GENUS_ALLOWED = [
  'campylobacter',
  'enterococcus_faecalis',
  'enterococcus_faecium',
  'escherichia_coli',
  'helicobacter_pylori',
  'klebsiella',
  'mycobacterium_tuberculosis',
  'neisseria_gonorrhoeae',
  'plasmodium_falciparum',
  'salmonella',
  'staphylococcus_aureus'
]

def ex = executionMetadata()

def getPointfinderParam(gsp) {
 try {  
    def genus_species = gsp ? gsp.toLowerCase() : ''
    def (genus, species) = genus_species.contains("_") ? genus_species.split('_') : [ genus_species, null ]
    if (POINFINDER_GENUS_ALLOWED.contains(genus_species)) {
        // genus_species allowed
        return genus_species;
    }       
    if (POINFINDER_GENUS_ALLOWED.contains(genus)) {
        // ALL genus allowed
        return genus
    }
    return ''
  } catch(Throwable t) {
      exit 1, "unexpected exception: ${t.asString()}"
  } 
}

process staramr {
    container "ghcr.io/genpat-it/staramr:0.9.1--8fe6b5a239"
    containerOptions = "--user root"
    tag "${riscd_input}/${plasmid_name}"
    memory { taskMemory( 2.GB, task.attempt ) }
    input:
      tuple val(riscd_input), path(plasmid_file)
      val(genus_species)
    output:
      path '**'
      path '{*.sh,*.log}', hidden: true
    publishDir mode: 'rellink', "${params.outdir}/plasmids/${plasmid_name}/result", pattern: 'result/{*.tsv,*.xlsx}', saveAs: { filename -> "${base}_${flattenPath(filename)}" }  
    publishDir mode: 'rellink', "${params.outdir}/plasmids/${plasmid_name}/result", pattern: 'result/hits/*', saveAs: { filename -> "hits/${base}_hits_${flattenPath(filename) -~ /_DS.+/}.fasta" }  
    publishDir mode: 'rellink', "${params.outdir}/plasmids/${plasmid_name}/meta", pattern: 'result/*.txt', saveAs: { filename -> "${base}_${flattenPath(filename)}" }  
    publishDir mode: 'rellink', "${params.outdir}/plasmids/${plasmid_name}/meta", pattern: '*.json'
    publishDir mode: 'rellink', "${params.outdir}/plasmids/${plasmid_name}/meta", pattern: '.command.log', saveAs: { "${base}.log" }
    publishDir mode: 'rellink', "${params.outdir}/plasmids/${plasmid_name}/meta", pattern: '.command.sh', saveAs: { "${base}.cfg" }
    script:
      plasmid_name = plasmid_file.getName() -~ /\.fa.*$/
      base = "${plasmid_name}_staramr"
      pointfinder_db = getPointfinderParam(genus_species)
      extra = pointfinder_db ? " --pointfinder-organism ${pointfinder_db}" : ''
      """
        sed 's/^>.*/>/g' ${plasmid_file} | awk '{for(i=1;i<=NF;i++){if(\$i~/^>/){\$i=">contig"++count}}} 1' > ${base}.fasta
        staramr search ${extra} -o result ${base}.fasta
      """
}

workflow module_plasmids {
    take: 
        assembly
        genus_species
    main:
        plasmids = step_4TY_plasmid__mobsuite(assembly).plasmids

        plasmids.multiMap { it ->
            riscd: it[0]
            plasmids: it[1]
        }.set { branched }

        input = branched.riscd.combine(branched.plasmids.flatten())
        staramr(input, genus_species)
}

workflow {
    module_plasmids(getSingleInput(), param('genus_species'))
}

nextflow.enable.dsl=2

include { parseMetadataFromFileName;executionMetadata;taskMemory } from '../functions/common.nf'
include { getInput;param;isCompatibleWithSeqType;isIlluminaPaired   } from '../functions/parameters.nf'
include { stepInputs;parseRISCD } from '../functions/common.nf'

def ex = executionMetadata()

process module_qc_nanoplot {
    container 'quay.io/biocontainers/nanoplot:1.41.3--pyhdfd78af_0'
    memory { taskMemory( 2.GB, task.attempt ) }
    cpus { [8, params.max_cpus as int].min() }
    tag "${md?.cmp}/${md?.ds}/${md?.dt}"
    maxForks 10
    when:
      isCompatibleWithSeqType(reads, ['nanopore'], task.process)
    input:
      tuple val(riscd_input), path(reads)
    output:
      path '*'
      path '{*.sh,*.log}', hidden: true 
    afterScript "echo '${stepInputs(riscd_input, md2, [dt: md2.dt], md2.acc, md2.met, [seq_type:'nanopore'])}' > ${base}_input.json"
    publishDir mode: 'rellink', "${params.outdir}/result", pattern: '{*.txt,*.html}', saveAs: { filename -> filename.replaceFirst("-DT\\d+_", "-${ex.dt}_") }
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '.command.log', saveAs: { "${base}.log" }
    publishDir mode: 'rellink', "${params.outdir}/meta", pattern: '.command.sh', saveAs: { "${base}.cfg" }

    script:
      md = parseMetadataFromFileName(reads.getName())
      md2 = parseRISCD(riscd_input)       
      base = "${md.ds}-${ex.dt}_${md.cmp}"
      """
      NanoPlot -t ${task.cpus} --fastq ${reads} --tsv_stats --no_static -o . -p ${base}_
      """
}

workflow {
    module_qc_nanoplot(getInput())
}

nextflow.enable.dsl=2

include { step_0SQ_rawreads__fastq } from '../steps/step_0SQ_rawreads__fastq'
include { step_1PP_trimming__trimmomatic } from '../steps/step_1PP_trimming__trimmomatic'
include { step_1PP_trimming__fastp } from '../steps/step_1PP_trimming__fastp'
include { step_3TX_class__kraken } from '../steps/step_3TX_class__kraken'
include { extractKey } from '../functions/common.nf'
include { getInput;hasFastqData;hasEnoughFastqData;isIlluminaPaired;isIonTorrent;isNanopore; } from '../functions/parameters.nf'
include { isBacterium } from '../functions/sampletypes.nf'

workflow module_reads_processing {
    take: 
      rawReads
    main:
        rawReads.branch {
            with_data: hasFastqData(it[1])
            no_reads: true
        }
        .set { rawreads_branched }
        step_0SQ_rawreads__fastq(rawreads_branched.with_data)        

        rawreads_branched.with_data.branch {
            illumina: isIlluminaPaired(it[1])
            ion: isIonTorrent(it[1])
            nanopore: isNanopore(it[1])
            other: true // won't be processed
        }
        .set { trimming_by_seqtype }

        trimming_by_seqtype.illumina.branch {
            bacteria: isBacterium(it)
            other: true 
        }
        .set { trimming_illumina }

        // trimmomatic
        trimmed_by_trimmomatic = step_1PP_trimming__trimmomatic(trimming_illumina.other).trimmed

        // fastp
        trimmed_by_fastp = step_1PP_trimming__fastp(trimming_by_seqtype.ion.mix(trimming_illumina.bacteria)).trimmed

        trimmed_by_trimmomatic.mix(trimmed_by_fastp).branch {
            with_data: hasEnoughFastqData(it[1])
            insufficient_number_of_reads: true
        }
        .set { trimmed_branched }
        step_3TX_class__kraken(trimmed_branched.with_data)
    emit:
        no_reads = rawreads_branched.no_reads
        trimmed_with_data = trimmed_branched.with_data
        insufficient_number_of_reads = trimmed_branched.insufficient_number_of_reads
}

workflow {
    module_reads_processing(getInput())
}

nextflow.enable.dsl=2

include { getVCFs;param;optionalOrDefault } from '../functions/parameters.nf'
include { taskMemory;getEmpty } from '../functions/common.nf'

if (getReportreeInputType() == 'alleles') {
  include { multi_clustering__reportree } from "../multi/multi_clustering__reportree_alleles"
  include { getAlleles as inputFn } from "../multi/multi_clustering__reportree_alleles"
} else if (getReportreeInputType() == 'alignment') {
  include { multi_clustering__reportree } from "../multi/multi_clustering__reportree_alignment"
  include { getInput as inputFn } from '../functions/parameters.nf'
} else {
  include { multi_clustering__reportree } from "../multi/multi_clustering__reportree_vcf"
  include { getVCFs as inputFn } from '../functions/parameters.nf'
}

def getReportreeInputType() {
    def res = param('multi_clustering__reportree__input')
    if (!(res in ['alleles', 'vcf', 'alignment'])) {
        exit 2, "params (multi_clustering__reportree__input) not valid"    
    } 
    return res
}

workflow {    
    multi_clustering__reportree(inputFn(),  param('metadata'), param('geodata'), optionalOrDefault('multi_clustering__reportree__nomenclature', getEmpty()));
}

nextflow.enable.dsl=2

include { step_2AS_filtering__seqio } from '../steps/step_2AS_filtering__seqio'
include { step_3TX_species__vdabricate } from '../steps/step_3TX_species__vdabricate'
include { extractKey } from '../functions/common.nf'
include { getInput;getReference;getDS } from '../functions/parameters.nf'

workflow module_scaffolds_filtering {    
    take: 
        assembled
        reference 
        abricatedatabase 
    main:
        assembled.cross(abricatedatabase) { extractKey(it) }
            .map { 
                [ it[0][0], it[0][1], it[1][1] ] //scaffolds, db
            }.set { scaffoldsAndDatabase }
        calls = step_3TX_species__vdabricate(scaffoldsAndDatabase)
        calls
            .cross(assembled) { extractKey(it) } // [ [riscd, calls], [riscd, assembly] ]
            .cross(reference) { extractKey(it) } // [ [ [riscd, calls], [riscd, assembly] ], [ key, riscd, refid refpath ] ]
            .multiMap { 
                calls: it[0][0]
                assembly: it[0][1]
                reference: it[1][1..3]
            }.set { filt }
        step_2AS_filtering__seqio(filt.calls, filt.assembly, filt.reference)
}

workflow {
    module_scaffolds_filtering(getInput(), getReference('fa'), Channel.of([ getDS(), 'viruses_TREF' ]))
}

nextflow.enable.dsl=2

include { extractKey } from '../functions/common.nf'
include { step_2AS_mapping__ivar } from '../steps/step_2AS_mapping__ivar'
include { getSingleInput;getReferences } from '../functions/parameters.nf'

workflow module_segmented {
    take: 
        reads
        reference 
    main:
        step_2AS_mapping__ivar(reads, reference)
    emit:
