workflow step_4TY_cgMLST__chewbbaca {
    take: 
      assembly
      genus_species
      schema
    main:
      //assume channels are already crossed
      chewbbaca_result = chewbbaca(assembly, genus_species, schema)      
      hashing(chewbbaca_result.alleles)
